from flask import Flask, request, jsonify
from psycopg2 import connect, sql
import os
from typing import List, Dict, Any

app = Flask(__name__)

# Configuration
DB_CONFIG = {
    'host': os.getenv('DB_HOST', 'localhost'),
    'port': os.getenv('DB_PORT', 5432),
    'database': os.getenv('DB_NAME', 'analytics'),
    'user': os.getenv('DB_USER', 'analytics_user'),
    'password': os.getenv('DB_PASSWORD', 'secure_password')
}

# Whitelisted tables and columns for security
ALLOWED_TABLES = {'users', 'orders', 'products', 'analytics_data'}
ALLOWED_COLUMNS = {
    'users': {'id', 'name', 'email', 'created_at'},
    'orders': {'id', 'user_id', 'amount', 'order_date'},
    'products': {'id', 'name', 'price', 'category'},
    'analytics_data': {'id', 'metric', 'value', 'timestamp'}
}

def validate_input(input_str: str, allowed_set: set) -> bool:
    """Validate that input is in allowed set"""
    return input_str in allowed_set

def build_query(table: str, columns: List[str], filters: Dict[str, Any]) -> tuple:
    """Build secure SQL query with parameters"""
    if not validate_input(table, ALLOWED_TABLES):
        raise ValueError("Invalid table name")
    
    # Validate columns
    for col in columns:
        if not validate_input(col, ALLOWED_COLUMNS.get(table, set())):
            raise ValueError(f"Invalid column name: {col}")
    
    # Build SELECT clause
    select_clause = sql.SQL("SELECT {}").format(
        sql.SQL(', ').join(sql.Identifier(col) for col in columns)
    )
    
    # Build FROM clause
    from_clause = sql.SQL("FROM {}").format(sql.Identifier(table))
    
    # Build WHERE clause
    where_conditions = []
    params = []
    
    for key, value in filters.items():
        if validate_input(key, ALLOWED_COLUMNS.get(table, set())):
            where_conditions.append(sql.SQL("{} = %s").format(sql.Identifier(key)))
            params.append(value)
    
    where_clause = sql.SQL("WHERE ") + sql.SQL(" AND ").join(where_conditions) if where_conditions else sql.SQL("")
    
    # Combine all parts
    query = sql.Composed([select_clause, from_clause, where_clause])
    
    return query, params

@app.route('/query', methods=['POST'])
def execute_query():
    try:
        data = request.get_json()
        
        table = data.get('table')
        columns = data.get('columns', ['*'])
        filters = data.get('filters', {})
        
        if not table:
            return jsonify({'error': 'Table name is required'}), 400
        
        # Build query
        query, params = build_query(table, columns, filters)
        
        # Execute query
        with connect(**DB_CONFIG) as conn:
            with conn.cursor() as cursor:
                cursor.execute(query, params)
                results = cursor.fetchall()
                
                # Get column names
                column_names = [desc[0] for desc in cursor.description]
                
                # Convert to list of dictionaries
                rows = [dict(zip(column_names, row)) for row in results]
                
                return jsonify({
                    'table': table,
                    'columns': column_names,
                    'data': rows,
                    'count': len(rows)
                })
                
    except Exception as e:
        return jsonify({'error': str(e)}), 400

if __name__ == '__main__':
    app.run(debug=False)